module CreateModelPackageOutput =
  struct
    type nonrec t =
      {
      modelPackageArn: ModelPackageArn.t
        [@ocaml.doc
          "The Amazon Resource Name (ARN) of the new model package."]}
    type nonrec error =
      [ `ConflictException of ConflictException.t 
      | `ResourceLimitExceeded of ResourceLimitExceeded.t 
      | `Unknown_operation_error of (string * string option) ]
    let context_ = "CreateModelPackageOutput"
    let make ~modelPackageArn = fun () -> { modelPackageArn }
    let error_of_json name json =
      match name with
      | "ConflictException" ->
          `ConflictException (ConflictException.of_json json)
      | "ResourceLimitExceeded" ->
          `ResourceLimitExceeded (ResourceLimitExceeded.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "ConflictException" ->
          `ConflictException (ConflictException.of_xml xml)
      | "ResourceLimitExceeded" ->
          `ResourceLimitExceeded (ResourceLimitExceeded.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `ConflictException e ->
          `Assoc
            [("error", (`String "ConflictException"));
            ("details", (ConflictException.to_json e))]
      | `ResourceLimitExceeded e ->
          `Assoc
            [("error", (`String "ResourceLimitExceeded"));
            ("details", (ResourceLimitExceeded.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("ModelPackageArn",
           (Some (ModelPackageArn.to_value x.modelPackageArn)))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let modelPackageArn =
        ModelPackageArn.of_xml
          (Xml.child_exn ~context:context_ xml_arg0 "ModelPackageArn") in
      make ~modelPackageArn ()
    let of_json json =
      let modelPackageArn =
        field_map_exn json "ModelPackageArn" ModelPackageArn.of_json in
      make ~modelPackageArn ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "Creates a model package that you can use to create Amazon SageMaker models or list on Amazon Web Services Marketplace, or a versioned model that is part of a model group. Buyers can subscribe to model packages listed on Amazon Web Services Marketplace to create models in Amazon SageMaker. To create a model package by specifying a Docker container that contains your inference code and the Amazon S3 location of your model artifacts, provide values for InferenceSpecification. To create a model from an algorithm resource that you created or subscribed to in Amazon Web Services Marketplace, provide a value for SourceAlgorithmSpecification. There are two types of model packages: Versioned - a model that is part of a model group in the model registry. Unversioned - a model package that is not part of a model group."]
